"""
NYT-discipline chart-type selector.

Given the SHAPE of the data and the QUESTION being asked, recommend a chart
type with a one-line rationale and an "anti-pattern" warning. This encodes
the choices the NYT graphics desk makes again and again — gleaned from
Gregor Aisch's portfolio retrospective (line > choropleth > small multiples
> bar > scatter), Amanda Cox's talks, Archie Tse's scrollytelling rules,
and the published Upshot back-catalog.

Inputs (loose dict):
  data_shape: {
    "n_rows": int,
    "n_series": int,             # number of distinct lines/categories
    "x_type": "time" | "ordinal" | "quantitative" | "geo",
    "y_type": "quantitative" | "ordinal" | "categorical",
    "has_parts_of_whole": bool,
    "has_geography": bool,
  }
  question: free text or one of the canonical question types:
    "change_over_time" | "compare_categories" | "show_distribution"
    "show_correlation"  | "show_composition"   | "rank_items"
    "where_is_it"       | "how_likely"

Output: dict with `recommended`, `why`, `avoid`, `nyt_examples`.

Discipline embedded:
  - Default to LINE for time-series. Anything else needs a reason.
  - Default to SMALL MULTIPLES when n_series > 5 with a shared x-axis.
  - NEVER pie. Use bar or stacked-bar instead (Aisch, Cox both on record).
  - For ranked lists: bar (horizontal) NOT lollipop unless the dots carry value.
  - For "where," use a locator map FIRST, choropleth only if values vary geographically AND matter.
  - For correlation: scatter with annotated outliers, not just a cloud.
  - Diverging color requires a meaningful zero. If you can't name the zero, use sequential.
"""

NYT_PATTERNS = {
    "change_over_time": {
        "single_series": {
            "recommended": "line chart",
            "why": "One line, one accent color, direct end-of-line label. The dominant NYT chart.",
            "avoid": "Don't use an area chart unless the magnitude (filled space) is the point. Areas exaggerate.",
            "nyt_examples": ["Daily COVID cases tracker (2020-23)", "U.S. unemployment rate"],
        },
        "few_series": {
            "recommended": "line chart with one hero series in accent + rest in grey",
            "why": "Color the line the story is about. Demote the rest to context.",
            "avoid": "Don't color every line — readers can only follow one or two simultaneously.",
            "nyt_examples": ["Excess mortality by country", "Inflation: U.S. vs. peers"],
        },
        "many_series": {
            "recommended": "small multiples (one panel per series, shared axes)",
            "why": "Past ~5 lines, a single chart becomes spaghetti. NYT defaults to small multiples here.",
            "avoid": "Don't pile 12 lines on one axis. Don't use a 12-color legend.",
            "nyt_examples": ["State-by-state COVID waves", "Country GDP growth trajectories"],
        },
    },
    "compare_categories": {
        "few": {
            "recommended": "horizontal bar chart, sorted by value",
            "why": "Labels fit horizontally; readers compare bar lengths effortlessly.",
            "avoid": "Vertical bars force label rotation. Don't.",
            "nyt_examples": ["Most-watched shows", "Highest-grossing films"],
        },
        "many": {
            "recommended": "dot plot or small bar chart with named outliers",
            "why": "Annotate the head and tail; leave the middle as context.",
            "avoid": "Don't show all 50 states with 50 tiny bars when only 6 matter.",
            "nyt_examples": ["State teacher pay rankings"],
        },
    },
    "show_distribution": {
        "default": {
            "recommended": "histogram or strip-plot (jittered dots)",
            "why": "A density curve hides the actual observations; dots show them.",
            "avoid": "Don't use box plots in journalism — general readers don't read them.",
            "nyt_examples": ["How rich is your school district?"],
        },
    },
    "show_correlation": {
        "default": {
            "recommended": "scatter plot with annotated outliers and a reference line",
            "why": "A naked cloud of dots tells the reader nothing. Annotate 3-5 named points.",
            "avoid": "Don't add a regression line without labeling its R² or saying what it means.",
            "nyt_examples": ["Income vs. life expectancy by country"],
        },
    },
    "show_composition": {
        "default": {
            "recommended": "stacked bar (one bar per time-period or category)",
            "why": "Stacks read fast. Pies don't — and they fail completely with >4 slices.",
            "avoid": "NEVER pie chart. NEVER 3D pie. NEVER donut unless the hole shows a total.",
            "nyt_examples": ["Federal budget composition over time"],
        },
        "over_time": {
            "recommended": "stacked area chart with the most-changing component on top",
            "why": "Put the volatile category where the eye lands — the upper baseline.",
            "avoid": "Streamgraphs are pretty but unreadable. Use only for vibes, never for numbers.",
            "nyt_examples": ["Sources of U.S. electricity generation"],
        },
    },
    "rank_items": {
        "default": {
            "recommended": "ranked horizontal bar chart, sorted descending",
            "why": "Sort by the variable being compared, not alphabetical. Length = value.",
            "avoid": "Don't sort alphabetically — readers can't compare. Don't use lollipops for ranks.",
            "nyt_examples": ["Highest-paid CEOs"],
        },
    },
    "where_is_it": {
        "single_point": {
            "recommended": "locator map (zoom in, label nearby cities/landmarks)",
            "why": "Where is it relative to things readers know? That's the question.",
            "avoid": "Don't drop a point on a world map — there's no reference.",
            "nyt_examples": ["Locator maps for breaking news"],
        },
        "many_values": {
            "recommended": "choropleth (sequential ramp) or hex-binned dot map",
            "why": "Choropleth when geography matters AND values vary. Hex-bin when raw density matters.",
            "avoid": "Don't choropleth when the story is about absolute counts in dense areas — use circles sized by value.",
            "nyt_examples": ["County-level election maps", "Heat map of U.S. extreme heat days"],
        },
    },
    "how_likely": {
        "default": {
            "recommended": "probability bar / Needle-style gauge / 100-icon array",
            "why": "Conveys uncertainty visually. The Needle's jitter literally animated uncertainty.",
            "avoid": "Don't show a single point estimate without showing the range around it.",
            "nyt_examples": ["The Election Needle (2016, 2020, 2024)", "Senate forecast gauges"],
        },
    },
}


def select_chart(question_type, data_shape):
    """Return the NYT-style recommendation for this data + question."""
    rules = NYT_PATTERNS.get(question_type)
    if not rules:
        return {
            "recommended": "line chart (default)",
            "why": "When unsure, start with a line chart on a time x-axis. It's the NYT default.",
            "avoid": "Don't reach for novelty (sankey, chord, radial) until line/bar fail.",
            "nyt_examples": [],
        }

    n_series = data_shape.get("n_series", 1)
    has_time = data_shape.get("x_type") == "time"

    if question_type == "change_over_time":
        if n_series == 1:
            return rules["single_series"]
        if n_series <= 5:
            return rules["few_series"]
        return rules["many_series"]

    if question_type == "compare_categories":
        return rules["few"] if data_shape.get("n_rows", 0) < 15 else rules["many"]

    if question_type == "where_is_it":
        return rules["many_values"] if n_series > 1 else rules["single_point"]

    if question_type == "show_composition":
        return rules["over_time"] if has_time else rules["default"]

    return rules.get("default", list(rules.values())[0])


CANONICAL_QUESTIONS = list(NYT_PATTERNS.keys())


if __name__ == "__main__":
    import sys, json
    if len(sys.argv) < 2:
        print("Usage: chart_selector.py <question_type> [json_data_shape]")
        print(f"  question_types: {CANONICAL_QUESTIONS}")
        sys.exit(1)
    q = sys.argv[1]
    shape = json.loads(sys.argv[2]) if len(sys.argv) > 2 else {}
    print(json.dumps(select_chart(q, shape), indent=2))
","description":"Given a question type and data shape, returns NYT-style chart-type recommendation with rationale, anti-pattern warning, and Times examples. Function: select_chart(question_type, data_shape)."},{"filename":"annotate.py","content":"#!/usr/bin/env python3
"""
Annotation linter — the single biggest delta between a default chart and an
NYT-grade chart is annotation. This module audits a chart spec and returns
specific, actionable fixes.

The NYT discipline:
  1. EVERY chart has a headline (declarative — tell me what to see).
  2. EVERY chart has a subtitle that names the unit and timeframe.
  3. EVERY chart has a source line.
  4. Lines are LABELED DIRECTLY at their endpoints, never via legend.
  5. The "hero" data point is annotated in-place ("peak: 4.2M cases, Jan 2022").
  6. Axis labels are written like English, not like spreadsheet column names.
  7. Y-axis 0 line is bold; gridlines are very pale; no axis spine.
  8. Where the data has a known inflection, ANNOTATE IT ("Lehman collapse",
     "vaccines available," "March 2020 lockdown") — context lives ON the chart.

Input: a dict describing the chart. Output: list of {severity, message, fix}.
"""

REQUIRED_FIELDS = {
    "headline":      "Declarative chart headline (not a label — a sentence: 'COVID deaths fell in 2023')",
    "subtitle":      "Subtitle naming unit + timeframe ('Weekly deaths, U.S., 2020-24')",
    "source":        "Source line ('Source: CDC. Note: ...')",
    "y_axis_unit":   "Y-axis unit ('Deaths per week', 'Share of vote, %')",
}

DISCIPLINE_CHECKS = [
    {
        "name": "direct_labels",
        "test": lambda c: c.get("series_count", 1) > 1 and not c.get("direct_labels"),
        "severity": "high",
        "message": "Multiple series shown via legend instead of direct labels.",
        "fix": "Label each line at its endpoint. Legends force the reader's eye back and forth — direct labels keep it on the data.",
    },
    {
        "name": "hero_color",
        "test": lambda c: c.get("series_count", 1) > 2 and c.get("colored_series", 0) == c.get("series_count"),
        "severity": "high",
        "message": "Every series is colored — no hero series.",
        "fix": "Color ONE series in the accent color. Demote the others to grey. The reader should know in one second which line matters.",
    },
    {
        "name": "annotation_for_inflection",
        "test": lambda c: c.get("has_known_inflection") and not c.get("inflection_annotated"),
        "severity": "high",
        "message": "A known historical inflection point in the data is not annotated.",
        "fix": "Add an inline label at the inflection ('March 2020: lockdowns', 'Sept 2008: Lehman'). Context lives ON the chart.",
    },
    {
        "name": "axis_label_humanized",
        "test": lambda c: c.get("y_axis_label", "").islower() or "_" in c.get("y_axis_label", ""),
        "severity": "medium",
        "message": "Y-axis label looks like a column name, not English.",
        "fix": "Replace 'unemployment_rate' with 'Unemployment rate (%)'. Write like a person, not a database.",
    },
    {
        "name": "zero_baseline",
        "test": lambda c: c.get("chart_type") == "bar" and c.get("y_min", 0) != 0,
        "severity": "high",
        "message": "Bar chart doesn't start at zero.",
        "fix": "Bar chart Y-axis MUST start at 0. Cropping it lies about magnitude. Use a dot plot if you need to crop.",
    },
    {
        "name": "gridline_chartjunk",
        "test": lambda c: c.get("gridlines_dark") or c.get("axis_spine"),
        "severity": "medium",
        "message": "Heavy gridlines or visible axis spines compete with the data.",
        "fix": "Gridlines pale (#e9e9e9). Remove the axis spine entirely. Only the data should carry weight.",
    },
    {
        "name": "color_ramp_choice",
        "test": lambda c: c.get("uses_rainbow") or c.get("uses_jet"),
        "severity": "critical",
        "message": "Rainbow / Jet color ramp detected.",
        "fix": "Replace with a monotonic-luminance ramp (sequential blue, viridis, or ColorBrewer). Rainbow lies about order to colorblind readers and to anyone printing greyscale.",
    },
    {
        "name": "tabular_nums",
        "test": lambda c: c.get("has_animated_values") and not c.get("uses_tabular_nums"),
        "severity": "low",
        "message": "Animated/changing numbers without tabular figures will jitter.",
        "fix": "Add `font-variant-numeric: tabular-nums;` so digit columns line up during transitions.",
    },
    {
        "name": "mobile_check",
        "test": lambda c: not c.get("tested_mobile"),
        "severity": "high",
        "message": "Chart hasn't been verified at 375px width (iPhone).",
        "fix": "NYT default-tests on iPhone first. If your annotations collide on mobile, rewrite them shorter.",
    },
    {
        "name": "interaction_required_for_value",
        "test": lambda c: c.get("requires_hover_for_critical_info"),
        "severity": "critical",
        "message": "Critical information is only visible on hover/click.",
        "fix": "Archie Tse rule: if you make the reader click, you'd better have a good reason. Crucial info MUST be visible without interaction. Use tooltips only for non-essential depth.",
    },
]


def audit(chart_spec):
    """Return a sorted list of issues."""
    issues = []
    for field, description in REQUIRED_FIELDS.items():
        if not chart_spec.get(field):
            issues.append({
                "severity": "high",
                "name": f"missing_{field}",
                "message": f"Missing {field}.",
                "fix": description,
            })
    for check in DISCIPLINE_CHECKS:
        try:
            if check["test"](chart_spec):
                issues.append({k: v for k, v in check.items() if k != "test"})
        except Exception:
            pass
    severity_order = {"critical": 0, "high": 1, "medium": 2, "low": 3}
    issues.sort(key=lambda i: severity_order.get(i["severity"], 4))
    return issues


def score(chart_spec):
    """0-100 NYT-discipline score for the chart spec."""
    issues = audit(chart_spec)
    penalties = {"critical": 25, "high": 10, "medium": 4, "low": 1}
    deduction = sum(penalties.get(i["severity"], 0) for i in issues)
    return max(0, 100 - deduction)


if __name__ == "__main__":
    import sys, json
    if len(sys.argv) < 2:
        # demo
        example = {
            "chart_type": "line",
            "series_count": 4,
            "colored_series": 4,
            "has_known_inflection": True,
            "inflection_annotated": False,
            "y_axis_label": "unemployment_rate",
            "tested_mobile": False,
        }
        print(json.dumps({"score": score(example), "issues": audit(example)}, indent=2))
    else:
        with open(sys.argv[1]) as f:
            spec = json.load(f)
        print(json.dumps({"score": score(spec), "issues": audit(spec)}, indent=2))
","description":"Lints a chart spec against NYT discipline (headline, subtitle, source, direct labels, hero color, zero baseline, etc). Functions: audit(spec) returns sorted issues; score(spec) returns 0-100."},{"filename":"render.py","content":"#!/usr/bin/env python3
"""
Render an NYT-discipline chart as a complete, standalone HTML page.

Produces a Times-grade artifact ready to publish via PublishWebpage. Charts
are rendered with Observable Plot (the d3-derived grammar Bostock co-authored
specifically for this kind of explanatory chart) plus the typography and color
discipline encoded in the sibling modules.

Usage:
    python3 render.py spec.json out.html

spec.json:
{
  "headline": "U.S. weekly deaths fell sharply in 2023",
  "subtitle": "Excess mortality, all causes. Source: CDC",
  "source": "Source: CDC Wonder. Chart: Hyperagent",
  "chart_type": "line" | "bar" | "area" | "scatter" | "small_multiples",
  "x_axis_label": "...",
  "y_axis_label": "Deaths per week",
  "data": [{"date": "2020-01-01", "value": 56000, "series": "U.S."}, ...],
  "hero_series": "U.S.",
  "annotations": [
    {"date": "2020-03-15", "value": 65000, "label": "Lockdowns begin"}
  ]
}
"""
import json
import sys
from pathlib import Path

# Import siblings
sys.path.insert(0, str(Path(__file__).parent))
from typography import GOOGLE_FONT_LINK, NYT_CSS  # noqa: E402
from palette import NYT_ACCENT, NYT_GREY_DARK  # noqa: E402


HTML_TEMPLATE = """<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>{title}</title>
{fonts}
<style>{css}
.chart-container {{ margin: 24px 0; }}
.chart-container svg {{ max-width: 100%; height: auto; display: block; }}
.annot-line {{ stroke: var(--nyt-text); stroke-width: 1; stroke-dasharray: 2 2; }}
.annot-label {{ fill: var(--nyt-text); font-weight: 500; }}
</style>
<script src="https://cdn.jsdelivr.net/npm/d3@7"></script>
<script src="https://cdn.jsdelivr.net/npm/@observablehq/plot@0.6"></script>
</head>
<body>
<div class="container">
  <h1 class="story-headline">{headline}</h1>
  <p class="dek">{subtitle}</p>
  <div class="chart-container" id="chart"></div>
  <div class="chart-source">{source}</div>
</div>
<script>
const spec = {spec_json};
const accent = {accent_json};
const grey = {grey_json};

function render() {{
  const data = spec.data.map(d => ({{
    ...d,
    date: d.date ? new Date(d.date) : d.date,
    value: +d.value,
  }}));

  const heroSeries = spec.hero_series;
  const isMulti = new Set(data.map(d => d.series)).size > 1;

  let marks = [];

  if (spec.chart_type === "line" || !spec.chart_type) {{
    marks.push(Plot.ruleY([0], {{ stroke: "#cccccc", strokeWidth: 1 }}));
    marks.push(Plot.line(data, {{
      x: "date",
      y: "value",
      stroke: isMulti ? "series" : () => accent,
      strokeWidth: d => (d.series === heroSeries ? 2.5 : 1.5),
    }}));
    if (isMulti && heroSeries) {{
      marks.push(Plot.text(
        data.filter(d => d.series === heroSeries),
        Plot.selectLast({{ x: "date", y: "value", text: "series", dx: 6, textAnchor: "start", fill: accent, fontWeight: 700 }})
      ));
    }}
  }} else if (spec.chart_type === "bar") {{
    marks.push(Plot.ruleY([0], {{ stroke: "#cccccc" }}));
    marks.push(Plot.barY(data, {{ x: "label", y: "value", fill: accent, sort: {{x: "-y"}} }}));
  }} else if (spec.chart_type === "scatter") {{
    marks.push(Plot.dot(data, {{ x: "x", y: "y", fill: accent, r: 4, fillOpacity: 0.7 }}));
  }} else if (spec.chart_type === "area") {{
    marks.push(Plot.areaY(data, {{ x: "date", y: "value", fill: accent, fillOpacity: 0.2 }}));
    marks.push(Plot.lineY(data, {{ x: "date", y: "value", stroke: accent, strokeWidth: 2 }}));
  }}

  // Annotations
  if (spec.annotations) {{
    spec.annotations.forEach(a => {{
      const ax = a.date ? new Date(a.date) : a.x;
      marks.push(Plot.ruleX([ax], {{ stroke: "#444", strokeDasharray: "2,2" }}));
      marks.push(Plot.text([{{x: ax, y: a.value, label: a.label}}], {{
        x: "x", y: "y", text: "label",
