HELPER_JS = r"""
// --- gliding, object-anchored tooltip (RULE C) ---
const tip = document.getElementById("tooltip");
function tipAtNode(node, html){
  const r = node.getBoundingClientRect();
  tip.innerHTML = html;
  tip.style.left = (r.left + r.width/2) + "px";
  tip.style.top  = r.top + "px";
  tip.style.opacity = 1;
